s = items;\r\n                            }\r\n                            return {\r\n                                ...category\r\n                            };\r\n                        });\r\n                    }\r\n                } catch (e) {\r\n                    this.$toast.error(\"Ha ocurrido un error\");\r\n                    console.log(e);\r\n                } finally {\r\n                    this.loading = false;\r\n                }\r\n            }, 350);\r\n        },\r\n        async getCategories() {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http.get(\"/items/categories/drag\");\r\n                if (response.status == 200) {\r\n                    const { categories } = response.data;\r\n                    this.categories = categories;\r\n                }\r\n            } catch (e) {\r\n                this.$toast.error(\"Ha ocurrido un error\");\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        async open() {\r\n            this.getCategories();\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n        },\r\n        drag(ev) {\r\n            ev.dataTransfer.setData(\"text\", ev.target.id);\r\n        },\r\n\r\n        allowDrop(ev) {\r\n            ev.preventDefault();\r\n        },\r\n        async updateCategory(itemId, categoryId) {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http(\r\n                    `/items/categories/update_category/${categoryId}/${itemId}`\r\n                );\r\n                if (response.status != 200) {\r\n                    this.$toast.error(\"Ha ocurrido un error\");\r\n                }\r\n            } catch (e) {\r\n                this.$toast.error(\"Ha ocurrido un error\");\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        drop(ev) {\r\n            ev.preventDefault();\r\n            let id = ev.target.id.split(\"-\");\r\n            let categoryDropId = id[0];\r\n            let data = ev.dataTransfer.getData(\"text\");\r\n            let [categoryId, itemid] = data.split(\"-\");\r\n            let item = this.categories\r\n                .find(category => category.id == categoryId)\r\n                .items.find(item => item.id == itemid);\r\n            this.updateCategory(itemid, categoryDropId);\r\n            this.categories = this.categories.map(category => {\r\n                if (category.id == categoryId) {\r\n                    category.items = category.items.filter(\r\n                        item => item.id != itemid\r\n                    );\r\n                }\r\n                if (category.id == categoryDropId) {\r\n                    category.items.push(item);\r\n                }\r\n\r\n                return {\r\n                    ...category\r\n                };\r\n            });\r\n        }\r\n    }\r\n};\r\n</script>\r\n\r\n<style>\r\n\r\n.scroll-drag{\r\n    overflow-y: scroll;\r\n    height: 350px;\r\n}\r\n\r\n</style>\r\n"],"sourceRoot":""}]);

